const clients = $('Collect Clients').first().json.clients;
const receivables = $input.all().map(i => i.json);

let intent = 'out_of_scope', clientName = null, phoneNum = null, receivableNo = null;
let clientId = null, reportYear = null, reportMonth = null;
try {
  const nluOutput = $('Intent Parse').first().json;
  const raw = nluOutput.text || nluOutput.output || nluOutput.content || JSON.stringify(nluOutput);
  const match = raw.match(/\{[\s\S]*?\}/);
  if (match) {
    const parsed = JSON.parse(match[0]);
    intent = parsed.intent    || 'out_of_scope';
    clientName = parsed.name      || null;
    phoneNum  = parsed.phone   || null;
    receivableNo = parsed.receivable_no || null;
    clientId = parsed.client_id   || null;
    reportYear = parsed.report_year ? Number(parsed.report_year) : null;
    reportMonth  = parsed.report_month  ? Number(parsed.report_month)  : null;
  }
} catch(e) { intent = 'out_of_scope'; }

// ── Report intents ───────────────────────────────────────────────────────────
if (intent === 'general_report') {
  return [{ json: { action: 'generate_report', tip: 'general' } }];
}
if (intent === 'weekly_report') {
  return [{ json: { action: 'generate_report', tip: 'weekly' } }];
}
if (intent === 'yearly_report') {
  const bugun = new Date();
  const yil = reportYear || (bugun.getFullYear() - 1);
  return [{ json: { action: 'generate_report', tip: 'yearly', yil } }];
}
if (intent === 'monthly_report') {
  const bugun = new Date();
  const yil = reportYear || (bugun.getMonth() === 0 ? bugun.getFullYear() - 1 : bugun.getFullYear());
  const ay  = reportMonth  || (bugun.getMonth() === 0 ? 12 : bugun.getMonth());
  return [{ json: { action: 'generate_report', tip: 'monthly', yil, ay } }];
}
if (intent === 'client_report') {
  let k = null;
  if (clientId) k = clients.find(ki => ki.client_id === clientId);
  else if (isim) k = clients.find(ki => ki.full_name && ki.full_name.toLowerCase().includes(clientName.toLowerCase()));
  if (!k) return [{ json: { response: `"${clientName || clientId || 'Client'}" not found.` } }];
  const kAls = receivables.filter(a => a.client_id === k.client_id || a.phone === k.phone);
  return [{ json: { action: 'generate_report', tip: 'client', kisi: k, kisi_alacaklar: kAls } }];
}

function formatAmount(n) { return (Number(n)||0).toLocaleString('en-US') + ' TL'; }
function statusEmoji(d) { return d==='Paid'?'✅':d==='Partial'?'🟡':d==='Unpaid'?'🔴':'⚪'; }
function parseDate(s) {
  if (!s) return null;
  const p = s.split('.');
  return p.length===3 ? new Date(p[2],p[1]-1,p[0]) : null;
}
function daysDiff(s) {
  const t = parseDate(s);
  return t ? Math.floor((Date.now()-t.getTime())/86400000) : 0;
}

let response = '';

if (intent === 'client_query' && isim) {
  const searchName = clientName.toLowerCase().trim();
  const found = clients.filter(k => k.full_name && k.full_name.toLowerCase().includes(searchName));
  if (found.length === 0) {
    response = `"${isim}" record not found.\nPlease enter the full name or phone number.`;
  } else if (found.length > 1) {
    response = `"${isim}" found ${found.length} people:\n\n`;
    found.forEach((k,i) => { response += `${i+1}. ${k.full_name} — ${k.company||'-'}\n   📞 ${k.phone}\n\n`; });
    response += 'Please re-query with the phone number.';
  } else {
    const k = found[0];
    const records = receivables.filter(a => a.phone === k.phone);
    response = `👤 *${k.full_name}* — ${k.company||'-'}\n`;
    if (k.notes) response += `📝 Note: ${k.notes}\n`;
    response += '\n';
    if (records.length === 0) {
      response += 'No records found.';
    } else {
      let total = 0;
      records.forEach(a => {
        const remaining = Number(a.remaining_amount)||0; total += remaining;
        response += `🏗️ ${a.project_name} / ${a.work_description}\n`;
        response += `💰 Total: ${formatAmount(a.total_amount)} | Kalan: ${formatAmount(remaining)}\n`;
        response += `📅 Vade: ${a.due_date||'-'} | ${statusEmoji(a.status)} ${a.status}\n\n`;
      });
      response += `─────────────────\n💳 *Total Remaining: ${formatAmount(total)}*`;
    }
  }
} else if (intent === 'phone_query' && telefon) {
  const searchPhone = String(phoneNum).replace(/[\s\-\(\)]/g,'');
  const k = clients.find(k => k.phone && k.phone.replace(/[\s\-\(\)]/g,'')===araTel);
  if (!k) {
    response = `No record found for this number: ${telefon}`;
  } else {
    const records = receivables.filter(a => a.phone===k.phone);
    response = `👤 *${k.full_name}* — ${k.company||'-'}\n\n`;
    let total = 0;
    records.forEach(a => {
      const remaining = Number(a.remaining_amount)||0; total += remaining;
      response += `🏗️ ${a.project_name} / ${a.work_description}\n`;
      response += `💰 Kalan: ${formatAmount(remaining)} | ${statusEmoji(a.status)} ${a.status}\n`;
      response += `📅 Vade: ${a.due_date||'-'}\n\n`;
    });
    response += `─────────────────\n💳 *Total Remaining: ${formatAmount(total)}*`;
  }
} else if (intent === 'receivable_query' && receivableNo) {
  const no = String(receivableNo).toUpperCase().trim();
  const a = receivables.find(a => a.receivable_no===no);
  if (!a) {
    response = `${no} receivable record not found.`;
  } else {
    const k = clients.find(k => k.phone===a.phone);
    response = `📋 *Alacak: ${a.receivable_no}*\n`;
    response += `👤 ${k?k.full_name:a.phone} — ${k?(k.company||'-'):'-'}\n\n`;
    response += `🏗️ ${a.project_name} / ${a.work_description}\n`;
    response += `💰 Total: ${formatAmount(a.total_amount)} | Kalan: ${formatAmount(a.remaining_amount)}\n`;
    response += `📅 Vade: ${a.due_date||'-'} | ${statusEmoji(a.status)} ${a.status}`;
    if (a.payment_date) response += ` | Paid: ${a.payment_date}`;
  }
} else if (intent === 'due_this_month') {
  const bugun = new Date();
  const buAyBaslangic = new Date(bugun.getFullYear(), bugun.getMonth(), 1);
  const buAySon = new Date(bugun.getFullYear(), bugun.getMonth() + 1, 0);
  const buAyVade = receivables
    .filter(a => {
      if (a.status === 'Paid') return false;
      const t = parseDate(a.due_date);
      return t && t >= buAyBaslangic && t <= buAySon;
    })
    .sort((a, b) => {
      const ta = parseDate(a.due_date), tb = parseDate(b.due_date);
      return (ta || 0) - (tb || 0);
    });
  if (buAyVade.length === 0) {
    response = '✅ No receivables due this month.';
  } else {
    let total = 0;
    const ayStr = bugun.toLocaleString('en-US', { month: 'long', year: 'numeric' });
    response = `📅 *${ayStr} Due* (${buAyVade.length} kayıt)\n\n`;
    buAyVade.forEach(a => {
      const k = clients.find(k => k.phone === a.phone);
      const remaining = Number(a.remaining_amount) || 0; total += remaining;
      response += `👤 ${k ? k.full_name : a.phone}\n`;
      response += `   ${a.project_name} — ${formatAmount(remaining)}\n`;
      response += `   📅 Vade: ${a.due_date}\n\n`;
    });
    response += `─────────────────\n💳 *Bu Ay Total: ${formatAmount(total)}*`;
  }
} else if (intent === 'overdue') {
  const overdueList = receivables
    .filter(a => a.status!=='Paid' && daysDiff(a.due_date)>0)
    .sort((a,b) => daysDiff(b.due_date)-daysDiff(a.due_date));
  if (overdueList.length === 0) {
    response = '✅ No overdue receivables.';
  } else {
    let total = 0;
    response = `🔴 *Overdue* (${overdueList.length} kayıt)\n\n`;
    overdueList.slice(0,15).forEach(a => {
      const k = clients.find(k => k.phone===a.phone);
      const remaining = Number(a.remaining_amount)||0; total += remaining;
      response += `👤 ${k?k.full_name:a.phone}\n`;
      response += `   ${a.project_name} — ${formatAmount(remaining)} (${daysDiff(a.due_date)} gün)\n\n`;
    });
    if (overdueList.length>15) response += `...ve ${overdueList.length-15} more records\n\n`;
    response += `─────────────────\n💳 *Total Overdue: ${formatAmount(total)}*`;
  }
} else if (intent === 'summary') {
  const odendi = receivables.filter(a => a.status==='Paid').length;
  const odenmedi = receivables.filter(a => a.status==='Unpaid').length;
  const kismi = receivables.filter(a => a.status==='Partial').length;
  const geciken = receivables.filter(a => a.status!=='Paid' && daysDiff(a.due_date)>0).length;
  const toplamKalan = receivables.reduce((s,a) => s+(Number(a.remaining_amount)||0), 0);
  response = `📊 *General Summary*\n\n`;
  response += `👥 Total Clients: ${clients.length}\n`;
  response += `📋 Total Records: ${receivables.length}\n\n`;
  response += `✅ Paid: ${odendi}\n🟡 Partial: ${kismi}\n🔴 Unpaid: ${odenmedi}\n⚠️ Overdue: ${geciken}\n\n`;
  response += `─────────────────\n💳 *Total Remaining: ${formatAmount(toplamKalan)}*`;
} else if (intent === 'help') {
  response = `How to query:\n\n• Type a client name → client debt status\n• Type a phone number → client debt status\n• *overdue* → overdue receivables\n• *summary* → grand total\n• A001, A002... → search by receivable number`;
} else {
  response = 'I cannot help with that. For receivables queries, please type a client name or phone number.';
}

return [{ json: { response } }];

return [
  { 
    json: { 
      clients: $input.all().map(i => i.json) 
    } 
  }
];

const tip    = $json.tip;
const chatId = $('Webhook').first().json.body.payload.from;
const company = process.env.COMPANY_NAME || 'Payment Tracking System';
const clients   = $('Google Sheets - Get Clients').all().map(i => i.json);
const receivables = $('Google Sheets - Get Receivables').all().map(i => i.json);

return [{ json: {
  tip,
  chatId,
  clients,
  receivables,
  yil: $json.yil || null,
  ay:  $json.ay  || null,
  kisi: $json.kisi || null,
  kisi_alacaklar: $json.kisi_alacaklar || null,
  company_name: company,
}}];

// Read sent reports
const logData = $('Collect Logs').first().json.logRows || [];
const sent = new Set(logData.map(r => `${r.report_type}_${r.period}`));

const baslangic = '2025-11';
const [basYil, basAy] = baslangic.split('-').map(Number);

const bugun = new Date();
const sonYil = bugun.getFullYear();
const sonAy  = bugun.getMonth() + 1;

const missing = [];

let y = basYil, m = basAy;
while (y < sonYil || (y === sonYil && m < sonAy)) {
  const period = `${y}-${String(m).padStart(2, '0')}`;
  if (!sent.has(`aylik_${donem}`)) missing.push({ tip: 'monthly', yil: y, ay: m, donem });
  m++; if (m > 12) { m = 1; y++; }
}

for (let yil = basYil; yil < sonYil; yil++) {
  const period = String(yil);
  if (!sent.has(`yillik_${donem}`)) missing.push({ tip: 'yearly', yil, ay: null, donem });
}

if (missing.length === 0) return [];
return missing.map(e => ({ json: e }));

// Prepare metadata for all missing reports (runOnceForAllItems)
const chatId = 'YOUR_WHATSAPP_CHAT_ID';
return $input.all().map(item => {
  const { tip, yil, ay, donem } = item.json;
  return { json: { tip, yil: yil || null, ay: ay || null, period, chatId } };
});

// Merge report-api HTTP responses with Build Report metadata
const apiItems     = $input.all();       // Call Report API outputs (base64, filename, summary)
const olusturItems = $('Build Report').all();  // Build Report outputs (chatId, tip, period)

return apiItems.map((apiItem, i) => {
  const rapor    = apiItem.json;
  const base64   = rapor.base64   || (rapor.rapor && rapor.rapor.base64)   || '';
  const filename = rapor.filename || (rapor.rapor && rapor.rapor.filename) || '';
  const summary     = rapor.summary     || (rapor.rapor && rapor.rapor.summary)     || '';

  const meta   = olusturItems[i] ? olusturItems[i].json : {};
  const chatId = meta.chatId || 'YOUR_WHATSAPP_CHAT_ID';
  const tip    = meta.tip    || '';
  const period  = meta.period  || '';

  return { json: { chatId, tip, period, base64, filename, summary } };
});

// After WAHA output - get base64 from Merge Reports and convert to binary
const wahaItems = $input.all();
const raporItems = $('Merge Reports').all();

return wahaItems.map((_, i) => {
  const rapor = raporItems[i] ? raporItems[i].json : {};
  const base64 = rapor.base64 || '';
  const filename = rapor.filename || 'rapor.pdf';
  return {
    json: {
      tip: rapor.tip || '',
      period: rapor.period || '',
      summary: rapor.summary || '',
      filename: filename
    },
    binary: {
      pdf: {
        data: base64,
        mimeType: 'application/pdf',
        fileName: filename,
        fileExtension: 'pdf'
      }
    }
  };
});

const chatId = $('Build Report Chatbot').first().json.chatId;
const tip    = $('Build Report Chatbot').first().json.tip;
return [{ json: {
  base64:   $json.base64,
  filename: $json.filename,
  summary:     $json.summary,
  chatId,
  tip,
  pdf:      $json.base64,
}}];

// After WAHA output - get base64 from Prepare Report Reply Chatbot and convert to binary
const wahaItems = $input.all();
const raporItems = $('Prepare Report Reply Chatbot').all();

return wahaItems.map((_, i) => {
  const rapor = raporItems[i] ? raporItems[i].json : {};
  const base64 = rapor.base64 || rapor.pdf || '';
  const filename = rapor.filename || 'rapor.pdf';
  const chatId = rapor.chatId || '';
  return {
    json: { tip: rapor.tip || '', summary: rapor.summary || '', filename, chatId, base64 },
    binary: {
      pdf: {
        data: base64,
        mimeType: 'application/pdf',
        fileName: filename,
        fileExtension: 'pdf'
      }
    }
  };
});

// Parse Gemini response
const raw = $json.candidates?.[0]?.content?.parts?.[0]?.text || '';

if (raw && raw.trim()) {
  let parsed;
  try { parsed = JSON.parse(raw); } catch(e) { parsed = { intent: 'out_of_scope' }; }
  const result = {
    intent:    parsed.intent    || 'out_of_scope',
    name:      parsed.name      || null,
    phone:     parsed.phone      || null,
    receivable_no: parsed.receivable_no || null,
    client_id:   parsed.client_id   || null,
    report_year: parsed.report_year || null,
    report_month:  parsed.report_month  || null,
  };
  return [{ json: { text: JSON.stringify(result) } }];
}

// Gemini failed - keyword fallback
const original = $('Webhook').item.json.body?.payload?.body || '';
const message = original.toLowerCase()
  .replace(/ğ/g,'g').replace(/ü/g,'u').replace(/ş/g,'s')
  .replace(/ı/g,'i').replace(/ö/g,'o').replace(/ç/g,'c');

let intent = 'out_of_scope';
let clientName = null, reportYear = null, reportMonth = null, phoneNum = null, receivableNo = null;

function extractName(text) {
  const temizle = ['borcu','borcunu','borclu','ne','kadar','nedir','alacagi','alacak',
    'odedi','mi','odeme','durumu','remaining','tutar','var','nasil','olan','raporu','sorgu'];
  const orig = original.split(/\s+/).filter(k => {
    const kl = k.toLowerCase().replace(/ğ/g,'g').replace(/ü/g,'u').replace(/ş/g,'s').replace(/ı/g,'i').replace(/ö/g,'o').replace(/ç/g,'c');
    return !temizle.includes(kl) && k.length > 1;
  });
  return orig.length > 0 ? orig.join(' ') : null;
}

// 1. Receivable number (A001 format)
const alacakMatch = message.match(/\ba\d{3}\b/);
if (alacakMatch) {
  intent = 'receivable_query';
  receivableNo = alacakMatch[0].toUpperCase();
}
// 2. Phone
else if (/\b0?5[0-9]{9}\b/.test(message.replace(/[\s\-]/g,''))) {
  intent = 'phone_query';
  const m = message.replace(/[\s\-]/g,'').match(/0?5[0-9]{9}/);
  if (m) phoneNum = m[0];
}
// 3. Client query - question for a SPECIFIC person (how much, debt - person-focused)
// "how much debt", "Ahmet borcu nedir", "Mehmet Demir ne kadar"
else if (/borcu\b|borcunu\b|ne kadar.*borclu|ne kadar.*alacak|odedi mi|odeme durumu/.test(message)) {
  intent = 'client_query';
  isim = extractName(message);
}
// 4. Yearly report - "rapor" keyword not required; year+summary/status or yearly is enough
else if (/yillik/.test(message) || (/\b(20\d{2})\b/.test(message) && /summary|durum|nasil|bakis|gitti|rapor/.test(message))) {
  intent = 'yearly_report';
  const m = message.match(/\b(20\d{2})\b/);
  if (m) reportYear = parseInt(m[1]);
}
else if (/rapor/.test(message) && /yillik|yil rapor|yili rapor/.test(message)) {
  intent = 'yearly_report';
  const m = message.match(/\b(20\d{2})\b/);
  if (m) reportYear = parseInt(m[1]);
}
// 5. General report
else if (/rapor/.test(message) && /genel|tum donem/.test(message)) {
  intent = 'general_report';
}
// 6. Weekly report
else if (/rapor/.test(message) && /haftalik|bu hafta/.test(message)) {
  intent = 'weekly_report';
}
// 7. Monthly report
else if (/rapor/.test(message)) {
  const aylar = {ocak:1,subat:2,mart:3,nisan:4,mayis:5,haziran:6,temmuz:7,agustos:8,eylul:9,ekim:10,kasim:11,aralik:12};
  let ayBulundu = null;
  for (const [ad, no] of Object.entries(aylar)) {
    if (message.includes(ad)) { ayBulundu = no; break; }
  }
  if (ayBulundu) {
    intent = 'monthly_report'; reportMonth = ayBulundu;
    const m = message.match(/\b(20\d{2})\b/);
    if (m) reportYear = parseInt(m[1]);
  } else {
    const yilM = message.match(/\b(20\d{2})\b/);
    if (yilM) { intent = 'yearly_report'; reportYear = parseInt(yilM[1]); }
    else { intent = 'weekly_report'; }
  }
}
// 8. Due this month
else if (/bu ay.*vade|bu ay.*odeme|bu ayki|bu ay kim/.test(message)) {
  intent = 'due_this_month';
}
// 9. Overdue - "who is in debt", "late", "did not pay"
else if (/vade.*daysLate|gecik|odeme.*yapmad|kimler.*borclu|borclu.*kimler/.test(message)) {
  intent = 'overdue';
}
// 10. Summary
else if (/summary|genel durum|toplam|kac alacak|butun kayit|genel bakis|kac kisi/.test(message)) {
  intent = 'summary';
}
// 11. Help
else if (/yardim|ne yapabilir|merhaba|selam|komut|nasil kullan/.test(message)) {
  intent = 'help';
}

const result = { intent, clientName, phoneNum, receivable_no: receivableNo, client_id: null, report_year: reportYear, report_month: reportMonth };
return [{ json: { text: JSON.stringify(result) } }];

const message = $('Webhook').item.json.body?.payload?.body || '';

const systemPrompt = `You are the NLU engine of a contractor receivables tracking system. Analyze the user's WhatsApp message and respond ONLY in the following JSON format, nothing else:

{"intent":"...","name":null,"phone":null,"receivable_no":null,"client_id":null,"report_year":null,"report_month":null}

=== QUERY INTENTS (returns text response, no PDF) ===
- client_query: Search by client name or company. Examples: "Ahmet Yılmaz borcu nedir", "Mehmet Demir ne kadar borçlu", "ABC İnşaat borcu"
- contact_query: Query email or contact info. Examples: "Ahmet Yılmaz'ın maili nedir"
- phone_query: Search by phone number. Examples: "0532... numaralı kişi"
- receivable_query: Search by receivable number (A001 format). Examples: "A023 alacağı", "A001 nedir"
- overdue: Past-due payments. Examples: "vadesi geçenler kimler", "geciken ödemeler", "kim ödeme yapmadı", "kimler borçlu"
- due_this_month: Payments due this month. Examples: "bu ay vadesi dolan kimler", "bu ay kim ödeme yapacak", "bu ayki vadeler"
- summary: General stats and overview (no year). Examples: "özet", "genel durum", "kaç alacak var", "toplam ne kadar", "bütün kayıtları göster", "genel bakış"
- help: System help. Examples: "yardım", "ne yapabilirsin", "merhaba", "nasıl kullanılır"
- out_of_scope: Unrelated questions. Examples: "hava nasıl", "ne zaman gelecek"

=== REPORT INTENTS (generates PDF and sends via email) ===
Even if the user does not say 'report/pdf/create/send', choose a report intent if that is clearly the intent.
- weekly_report: Weekly PDF report request. Examples: "haftalık rapor gönder", "bu haftanın raporunu oluştur", "haftalık durum"
- monthly_report: Monthly PDF report. Fill report_month (1-12) and report_year. Examples: "ocak raporu", "şubat aylık raporu", "mart 2025 raporu", "ocak ayı durumu"
- yearly_report: Yearly PDF report. Fill report_year. Examples: "2025 yılı rapor gönder", "yıllık raporu oluştur", "2024 raporu", "2026 yılı özet", "2026 yılı durumu", "yıllık durum", "2025 nasıl gitti", "yıl özeti"
- general_report: All-time PDF report. Examples: "genel rapor gönder", "tüm dönem raporu oluştur"
- client_report: PDF report for a specific client. Fill name or client_id. Examples: "Ahmet Yılmaz raporu gönder", "K005 raporu oluştur"

=== CRITICAL RULES ===
1. Specific year (2024, 2025, 2026...) + summary/status/report/how → yearly_report, fill report_year
2. "show all records", "overview", "how much receivable" (no year) → summary
3. "bu ay vadesi dolan", "bu ay kimlerin ödemeleri yaklaşıyor" → due_this_month
4. Emin olamadığında out_of_scope — choose the closest intent instead
5. "özet" kelimesi tek başına gelirse → summary; yıl ile gelirse ("2026 yılı özet") → yearly_report`;

return [{
  json: {
    contents: [{ role: "user", parts: [{ text: message }] }],
    systemInstruction: { parts: [{ text: systemPrompt }] },
    generationConfig: { responseMimeType: "application/json", temperature: 0.1 }
  }
}];

const clientsRaw = $('Collect Reminder Clients').first().json.clients;
const receivablesRaw = $input.all().map(i => i.json);

const receivables = receivablesRaw.map(a => {
  const odenen = parseFloat(String(a.paid_amount || 0).replace(',', '.')) || 0;
  const toplam = parseFloat(String(a.total_amount || 0).replace(',', '.')) || 0;
  return {
    ...a,
    status: odenen >= toplam ? 'Paid' : (odenen <= 0 ? 'Unpaid' : 'Partial'),
    remaining_amount: Math.max(0, toplam - odenen),
  };
});

const clientsMap = {};
