function parseDate(s) {
  if (!s || s === '-') return null;
  s = String(s).trim();
  const p = s.split('.');
  if (p.length === 3 && p[0].length <= 2) {
    const d = new Date(parseInt(p[2]), parseInt(p[1]) - 1, parseInt(p[0]));
    return isNaN(d.getTime()) ? null : d;
  }
  if (s.includes('-')) {
    const d = new Date(s.slice(0, 10));
    return isNaN(d.getTime()) ? null : d;
  }
  return null;
}

function daysDiff(vade) {
  if (!vade) return null;
  return Math.floor((bugun.getTime() - vade.getTime()) / 86400000);
}

function reminderDue(daysLate) {
  if (daysLate < 0) return false;
  return daysLate === 0 || daysLate === 1 || daysLate === 3 || (daysLate >= 5 && daysLate % 5 === 0);
}

function formatAmount(n) {
